#include <bits/stdc++.h>
using namespace std;
int gtj[1001][1001];
vector<int> gtb[1001];
int main(){
	int n,m;
	cin>>n>>m;
	for(int i=0;i<m;i++){
		int u,v;
		cin>>u>>v;
		gtj[u][v]=1;
		gtj[v][u]=1;
		gtb[u].push_back(v);
		gtb[v].push_back(u);
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++)cout<<gtj[i][j]<<' ';
		cout<<endl;
	}
	for(int i=1;i<=n;i++){
		cout<<gtb[i].size()<<' ';
		for(int j=0;j<=n;j++)if(gtj[i][j])cout<<j<<' ';
		cout<<endl;
	}
	return 0;
}
